// Paso 1: Obtener el item JSON de entrada
const item = $input.first().json;

// Paso 2: Encontrar la clave que comienza con "session_"
const sessionKey = Object.keys(item).find(key => key.startsWith("session_"));

// Paso 3: Verificar si se encontró la clave antes de procesarla
if (!sessionKey) {
  // Si no existe sessionKey, retornar valores vacíos o un error controlado
  return [
    {
      json: {
        sessionID: '',
        sessionValue: '',
        error: 'No se encontró ninguna clave que comience con "session_"'
      }
    }
  ];
}

// Paso 4: Remover el prefijo "session_" para extraer el sessionID
const sessionID = sessionKey.replace("session_", "");

// Paso 5: Obtener el valor UUID de la sesión
const sessionValue = item[sessionKey];

// Paso 6: Retornar los datos como salida del nodo
return [
  {
    json: {
      sessionID,
      sessionValue
    }
  }
];

// Texto original do usuário
const text =
  ($json.text || $json.message || $json.userText || "").toLowerCase();

// Timezone correta
const tz = "Europe/Madrid";
const now = new Date(
  new Date().toLocaleString("en-US", { timeZone: tz })
);

// Zera hora para comparação
now.setHours(0, 0, 0, 0);

let date = null;

if (text.includes("mañana")) {
  date = new Date(now);
  date.setDate(date.getDate() + 1);
} else if (text.includes("hoy")) {
  date = new Date(now);
}

// Se não detectou relativo, mantém o que já veio (ex: data explícita)
if (!date && $json.data) {
  return [{ json: { ...$json } }];
}

if (!date) {
  return [{ json: { ...$json } }];
}

// Formata YYYY-MM-DD
const yyyy = date.getFullYear();
const mm = String(date.getMonth() + 1).padStart(2, "0");
const dd = String(date.getDate()).padStart(2, "0");

return [
  {
    json: {
      ...$json,
      data: `${yyyy}-${mm}-${dd}`,
    },
  },
];
